from flask import Flask, request, jsonify
import secrets, datetime
from functools import wraps

app = Flask(__name__)

# In-memory user and token stores
USERS = {
    "alice": "password123",
    "bob": "s3cret"
}
TOKENS = {}  # token -> {"user": str, "expires": datetime}

TOKEN_TTL = datetime.timedelta(hours=1)


def create_token(username):
    token = secrets.token_hex(32)
    TOKENS[token] = {
        "user": username,
        "expires": datetime.datetime.utcnow() + TOKEN_TTL
    }
    return token


def token_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        auth = request.headers.get("Authorization", "")
        if not auth.startswith("Bearer "):
            return jsonify(error="missing or invalid token"), 401
        token = auth.split()[1]
        record = TOKENS.get(token)
        if not record:
            return jsonify(error="invalid token"), 401
        if record["expires"] < datetime.datetime.utcnow():
            TOKENS.pop(token, None)
            return jsonify(error="token expired"), 401
        request.user = record["user"]
        return fn(*args, **kwargs)
    return wrapper


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json() or {}
    user, pwd = data.get("username"), data.get("password")
    if not user or not pwd:
        return jsonify(error="username & password required"), 400
    if USERS.get(user) != pwd:
        return jsonify(error="invalid credentials"), 401
    token = create_token(user)
    return jsonify(token=token, expires_in=TOKEN_TTL.total_seconds())


@app.route("/logout", methods=["POST"])
@token_required
def logout():
    token = request.headers["Authorization"].split()[1]
    TOKENS.pop(token, None)
    return jsonify(message="logged out")


@app.route("/protected")
@token_required
def protected():
    return jsonify(message=f"hello, {request.user}! this is a protected endpoint")


if __name__ == "__main__":
    app.run(debug=True)